#!/usr/bin/env bash
load_stage_07(){ set_stage 7 "실시간 로그 추적" "배포 직후 에러가 재현되는지 보며 확인해야 합니다." "앱 로그를 실시간 추적 모드로 여세요." "tail -f, tail -n" "tail 옵션 파일명" "tail -f는 파일 끝을 따라가며 새 로그를 계속 보여줍니다." "장애 재현 중 실시간 로그 관찰은 원인과 조치 효과를 즉시 확인하게 해줍니다." "tail -f로 재현 시점의 로그를 추적해 조치 검증 준비를 마쳤다." "-f 옵션을 붙여 계속 따라가세요." "tail 명령에 실시간 추적 옵션과 로그 파일 경로를 붙입니다." '^tail[[:space:]]+-f[[:space:]]+logs/app\.log$' '^tail[[:space:]]+-n[[:space:]]+[0-9]+[[:space:]]+-f[[:space:]]+logs/app\.log$'; }
